sqlMap.select:
/* CarMgtDAO.selectCarDriveList */ select DRIVE_IDX , d.CAR_IDX , DRIVE_NO , PURPOSE_CD , convert(varchar(10), DRIVE_DATE, 121) as drive_date , DEP_POINT , DEP_ACC_DIST , ARR_POINT , ARR_ACC_DIST , DRIVE_DIST , DRIVE_WORK_DIST , d.REMARK , dept.deptName as dept_nm , c.DUTY , d.user_id , d.com_cd , d.dept_cd , u.user_nm , cd.code_name as purpose , d.distance , case when h.HOLIDAY is null then 0 else 1 end as holidayYn , datename(dw, drive_date) as yoil from tb_car_drive d WITH(NOLOCK) inner join tb_car c WITH(NOLOCK) on d.CAR_IDX = c.idx left join FIM.dbo.tb_user u WITH(NOLOCK) on d.user_id = u.user_id left join tb_code cd WITH(NOLOCK) on cd.code_type = 'drivePurpose' and cd.code = d.purpose_cd left join sgerp.dbo.SG_VHRIFDeptQuery dept WITH(NOLOCK) on d.com_cd = dept.companyseq and dept.deptSeq = d.DEPT_CD left join e_hr.dbo.TB_HOLIDAY h WITH(NOLOCK) on d.DRIVE_DATE = h.HOLIDAY_DATE and h.COM_CD = 'H0000000' where CAR_IDX = #carIdx# and convert(varchar, d.drive_date, 23) like #year# + '-' + #month# + '%'
and d.DRIVE_DATE >= convert(varchar, (select isnull(max(DRIVE_DATE), getdate()) from TB_CAR_DRIVE WITH(NOLOCK) where CAR_IDX = #carIdx# and year = #year# ) - convert(int, #recentDays#) , 23)
order by DRIVE_DATE

sqlMap.update:
/* CarMgtDAO.updateCarNo */ with drive as ( select drive_idx,
de.COMPANY_ID /* HSLA-7948 : [EFIS] EKPORG 참조 로직 추가 처리 ( 2022-06-13 : 김연준 ) */ + '-' + replace(substring(convert(varchar(10), drive_date, 121), 3, 8), '-', '') + '-' + dbo.fn_lpad(convert(varchar, car_idx), 3, '0') + '-' + dbo.fn_lpad(convert(varchar,row_number() over(order by arr_acc_dist )),3, '0') as drive_no FROM tb_car_drive d WITH(NOLOCK) inner join tb_car c WITH(NOLOCK) on d.car_idx = c.idx left join sgerp.dbo.SG_VHRIFDeptQuery v WITH(NOLOCK) on ComCd = DeptCd and v.companyseq = c.com_cd
left join FIM.dbo.TB_COMPANY de WITH(NOLOCK) on v.comCd = de.com_Cd /* HSLA-7948 : [EFIS] EKPORG 참조 로직 추가 처리 ( 2022-06-13 : 김연준 ) */ where drive_date = #driveDate# and car_idx = #carIdx# ) update tb_car_drive set drive_no = drive.drive_no from tb_car_drive b, drive where b.DRIVE_IDX = drive.drive_idx

sqlMap.delete:
/* CarMgtDAO.deleteCarCost */ delete from tb_car_cost where term_idx in ( select term_idx from tb_car_user_term where car_idx = #carIdx# and term_idx not in
#termIdx_arr[]#
)

sqlMap.select:
/* CarMgtDAO.selectCarUserTermCost */
select count(*) as cnt
from tb_car_cost WITH(NOLOCK)
where term_idx = #termIdx#
